
#include "svg_helper.h"
int main(){string stem="05_bubble_sort",title="05 Bubble Sort"; vector<vector<int>> frames={{5,3,8,1,4,7},{3,5,8,1,4,7},{3,5,1,8,4,7},{3,5,1,4,8,7},{3,5,1,4,7,8},{3,1,5,4,7,8},{3,1,4,5,7,8},{1,3,4,5,7,8},{1,3,4,5,7,8}}; vector<pair<int,int>> cmp={{0,1},{1,2},{2,3},{3,4},{4,5},{1,2},{2,3},{0,1},{-1,-1}}; vector<string> f={"adjacent compare only","swap if left > right","largest bubbles to right","one pass fixes suffix"}; for(int k=0;k<frames.size();++k){int W=1140,H=680; set<int> hot,done; if(cmp[k].first>=0){hot.insert(cmp[k].first);hot.insert(cmp[k].second);} for(int i=frames[k].size()-(k>=4?1:0)-(k>=7?1:0); i<frames[k].size(); ++i) if(i>=0) done.insert(i); string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - compare adjacent pair then swap if inverted"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Bubble sort pass: compare neighbors from left to right",17,"#123","700"); s+=arr(frames[k],90,185,hot,done); if(cmp[k].first>=0){int x1=90+cmp[k].first*58+29,x2=90+cmp[k].second*58+29; s+=arrow(x1,275,x2,275,"#d92d27",5); s+=T((x1+x2)/2-35,310,"compare",15,"#b91c1c","700");} s+=bars(frames[k],100,520,hot,done); s+=T(90,585,"Bubble-specific visual: red arrow moves only between adjacent cells; green suffix is already bubbled/fixed.",16,"#111827","700"); s+=sidebar(k+1,frames.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
